// Création d'un formulaire HTML
const form = document.createElement('form');
form.setAttribute('method', 'post');
form.setAttribute('action', '#');

// Création d'un champ de texte
const input = document.createElement('input');
input.setAttribute('type', 'text');
input.setAttribute('name', 'userInput');
input.setAttribute('placeholder', 'Saisissez du texte ici...');

// Création d'un bouton de soumission
const button = document.createElement('button');
button.setAttribute('type', 'submit');
button.textContent = 'Sauvegarder';

// Ajout des éléments au formulaire
form.appendChild(input);
form.appendChild(button);

// Ajout du formulaire au body
document.body.appendChild(form);

// Gestion de la soumission du formulaire
form.addEventListener('submit', function(event) {
    event.preventDefault(); // Empêche le rechargement de la page

    const userInput = input.value.trim(); // Récupère le texte saisi

    if (userInput) {
        // Sauvegarde dans le localStorage
        localStorage.setItem('userInput', userInput);
        alert('Texte sauvegardé : ' + userInput);
    } else {
        alert('Veuillez saisir du texte.');
    }
});
